import{c as a,Q as i,j as E,m as n}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"创建/编辑任务","description":"","frontmatter":{},"headers":[],"relativePath":"using-system/task-management/create-task/index.md","filePath":"using-system/task-management/create-task/index.md"}'),e={name:"using-system/task-management/create-task/index.md"};function s(l,t,p,A,r,B){return i(),E("div",null,[...t[0]||(t[0]=[n('<h1 id="创建-编辑任务" tabindex="-1">创建/编辑任务 <a class="header-anchor" href="#创建-编辑任务" aria-label="Permalink to &quot;创建/编辑任务&quot;">​</a></h1><h2 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h2><p>本模块用于快速创建资管任务，同时支持对已发布、未完成任务进行二次编辑修改，完善任务内容、调整执行规则与权限配置，适配日常资管任务派发与流程管控需求。</p><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li><p>在首页点击「新建」按钮，弹出任务创建弹窗 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522144948718.png" alt="首页"></p><p>或者，在资管任务页点击「新建任务」按钮，弹出任务创建弹窗 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522145059679.png" alt="资管任务页"></p><p><img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522145155364.png" alt="任务创建弹窗"></p></li><li><p>填写「任务标题」（必填），明确任务核心内容与业务场景</p></li><li><p>点击「添加分派对象」，选择任务的执行人员/执行部门 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522145502128.png" alt="添加分派对象弹窗"><img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522145534130.png" alt=""></p></li><li><p>点击「添加截止时间」，设置任务的最晚完成节点；</p><p>可通过下拉菜单调整「任务优先级」（一般/紧急/重要）； <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522151106736.png" alt=""></p><p>可点击督办图标标记为「督办任务」 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522151136933.png" alt=""></p></li><li><p>点击「添加描述」，补充任务的详细说明、业务背景、执行要求等信息 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522151427368.png" alt=""></p></li><li><p>（可选）通过底部工具栏添加附件、关联文件或复制任务模板，完善任务信息 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522151856780.png" alt="添加附件/关联文件"><img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522151547870.png" alt=""></p></li><li><p>核对全部信息无误后，点击右下角【创建】按钮完成任务发布； （编辑已有任务时，修改信息后点击保存即可生效。）</p></li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ol><li>任务标题为必填项，未填写时无法完成创建</li><li>任务分派对象支持单选/多选，可同时指派给多人或多个部门协同执行</li><li>已创建的任务，若已被接收人处理/开始执行，部分关键配置（如分派对象、截止时间）的修改会同步推送通知</li><li>标记为督办的任务，会进入督办任务列表，系统将按预设规则自动提醒督办人与执行人</li></ol>',7)])])}const d=a(e,[["render",s]]);export{c as __pageData,d as default};
